cat > /app/src/server.ts <<'BUN_BENCH_SOLUTION_EOF'
const port = Number(Bun.env.PORT ?? 3000);

type SocketData = { channel: string };
type Buffered = { seq: number; data: unknown };

// channel -> ordered buffer of all published messages
const buffers = new Map<string, Buffered[]>();
// channel -> last assigned sequence number (0 means none yet)
const lastSeq = new Map<string, number>();
// channel -> set of currently-connected live subscribers
const subscribers = new Map<string, Set<Bun.ServerWebSocket<SocketData>>>();

function nextSeq(channel: string): number {
  const next = (lastSeq.get(channel) ?? 0) + 1;
  lastSeq.set(channel, next);
  return next;
}

const server = Bun.serve<SocketData>({
  port,
  async fetch(request, srv) {
    const url = new URL(request.url);

    if (request.method === "GET" && url.pathname === "/healthz") {
      return Response.json({ ok: true }, { status: 200 });
    }

    if (request.method === "POST" && url.pathname === "/publish") {
      let body: unknown;
      try {
        body = await request.json();
      } catch {
        return Response.json({ error: "invalid_json" }, { status: 400 });
      }
      const record = body as Record<string, unknown> | null;
      if (!record || typeof record.channel !== "string" || !("data" in record)) {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      const channel = record.channel;
      const data = record.data;
      const seq = nextSeq(channel);
      let buf = buffers.get(channel);
      if (!buf) {
        buf = [];
        buffers.set(channel, buf);
      }
      buf.push({ seq, data });

      const subs = subscribers.get(channel);
      if (subs) {
        const payload = JSON.stringify({ seq, data });
        for (const ws of subs) ws.send(payload);
      }
      return Response.json({ channel, seq }, { status: 201 });
    }

    if (url.pathname === "/ws") {
      const channel = url.searchParams.get("channel");
      if (!channel) {
        return Response.json({ error: "channel_required" }, { status: 400 });
      }
      const rawLast = url.searchParams.get("last_seq");
      let lastSeen = 0;
      if (rawLast !== null) {
        if (!/^\d+$/.test(rawLast)) {
          return Response.json({ error: "invalid_last_seq" }, { status: 400 });
        }
        lastSeen = Number(rawLast);
      }
      const ok = srv.upgrade(request, { data: { channel, lastSeen } as SocketData & { lastSeen: number } });
      if (ok) return undefined;
      return Response.json({ error: "upgrade_failed" }, { status: 426 });
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
  websocket: {
    open(ws) {
      const data = ws.data as SocketData & { lastSeen: number };
      const { channel, lastSeen } = data;

      // Register as a live subscriber and replay synchronously in the same
      // turn. Because open() runs to completion without yielding, no publish
      // can interleave: every replayed message has seq > lastSeen, and every
      // subsequent live message has a strictly greater seq. No gaps, no dupes.
      let subs = subscribers.get(channel);
      if (!subs) {
        subs = new Set();
        subscribers.set(channel, subs);
      }
      subs.add(ws);

      // Replay buffered messages with seq > lastSeen in ascending order.
      const buf = buffers.get(channel) ?? [];
      for (const entry of buf) {
        if (entry.seq > lastSeen) {
          ws.send(JSON.stringify({ seq: entry.seq, data: entry.data }));
        }
      }
    },
    message() {
      // Subscribers do not send messages; ignore any input.
    },
    close(ws) {
      const { channel } = ws.data;
      const subs = subscribers.get(channel);
      if (!subs) return;
      subs.delete(ws);
      if (subs.size === 0) subscribers.delete(channel);
    },
  },
});

console.log(`seqnum-resume reference listening on ${server.port}`);
BUN_BENCH_SOLUTION_EOF
